        AND n.topic_id = #{topicId}
        AND n.title LIKE CONCAT('%', #{title}, '%')
        AND n.is_published = #{isPublished}
        AND n.is_pass = #{isPass}
        AND n.is_missing_info = #{isMissingInfo}

